let totalPreTax = this.totalPreTaxAmount ?? 0;
let totalHst = this.totalHst ?? 0;
return parseFloat(totalPreTax) + parseFloat(totalHst);

let submitButtonFake = this.submitButtonFake;

let dataIframe = $('#iframe-psTools').contents().find('#iframe-items').val() ?? '';
if (dataIframe !='') {
    dataIframe = JSON.parse(dataIframe);
}
return dataIframe;

